const data = $input.first().json;
const docs = data.result || [];
const todasLasCategorias = data.existing_categories || ['Sin clasificar'];

if (docs.length === 0) {
  return [{ json: { error: 'No hay documentos' } }];
}

// Filtrar: solo categorías cortas (<=4 palabras, <=40 chars)
const categorias = todasLasCategorias.filter(cat => {
  const palabras = cat.trim().split(/\s+/);
  return palabras.length <= 4 && cat.length <= 40;
});

if (!categorias.includes('Sin clasificar')) {
  categorias.push('Sin clasificar');
}

// Formatear documentos para el prompt
let listaDocs = '';
for (const doc of docs) {
  const tags = doc.metadata?.tags || [];
  const preview = (doc.text || '').slice(0, 400);
  listaDocs += `\nID: ${doc.id}\nArchivo: ${doc.metadata?.filename || doc.id}\nEtiquetas: ${tags.join(', ') || 'ninguna'}\nTexto: ${preview}\n---`;
}

const prompt = `Eres un asistente que categoriza documentos. Tu tarea es analizar cada documento y asignarle la categoría más apropiada.\n\nCATEGORÍAS DISPONIBLES (usa EXACTAMENTE estos nombres):\n${categorias.join('\n')}\n\nREGLAS:\n- Analiza las etiquetas y el texto del documento\n- Elige la categoría que mejor describa el tema principal del documento\n- Si ninguna categoría encaja claramente, usa: Sin clasificar\n- NO inventes categorías nuevas, solo usa las de la lista de arriba\n\nDOCUMENTOS:\n${listaDocs}\n\nResponde ÚNICAMENTE con un array JSON válido, sin texto extra, sin explicaciones, sin bloques de código:\n[\n  {"id": "id_documento", "category": "NombreCategoria", "reason": "motivo breve"},\n  ...\n]`;

// Construir el body completo serializado para evitar problemas de interpolación en n8n
const body = JSON.stringify({
  model: 'goekdenizguelmez/JOSIEFIED-Qwen3:14b-q4_k_m',
  prompt: prompt,
  stream: false,
  think: false,
  options: {
    num_ctx: 4096,
    temperature: 0.1
  }
});

return [{ json: { body, total: docs.length, categorias_disponibles: categorias } }];

const raw = $input.first().json.response || '';

let decisiones = [];

try {
  const match = raw.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  if (match) {
    decisiones = JSON.parse(match[0]);
  } else {
    decisiones = JSON.parse(raw.trim());
  }
} catch (e) {
  return [{ json: { error: 'No se pudo parsear respuesta de Qwen', raw: raw.slice(0, 300) } }];
}

const validas = decisiones.filter(d => d.id && d.category);
console.log(`Qwen categorizó ${validas.length} documentos`);
return validas.map(d => ({ json: d }));
